import json
import time
from typing import Any, Dict, Optional

class HttpResponse:
    def __init__(self, status_code: int, headers: Optional[Dict[str, str]] = None, body: Optional[str] = None):
        self.status_code = status_code
        self.headers = headers if headers is not None else {}
        self.body = body
        self.response_time = None

    def record_timing(self, start_time: float):
        """Records the time taken for the response."""
        self.response_time = time.time() - start_time

    def is_success(self) -> bool:
        """Checks if the response status code indicates success."""
        return 200 <= self.status_code < 300

    def parse_json(self) -> Optional[Dict[str, Any]]:
        """Parses the response body as JSON and returns the resulting dictionary."""
        if self.body:
            try:
                return json.loads(self.body)
            except json.JSONDecodeError:
                return None
        return None

    def pretty_print(self) -> str:
        """Returns a pretty-printed string representation of the HTTP response."""
        response_info = {
            "Status Code": self.status_code,
            "Headers": self.headers,
            "Body": self.body,
            "Response Time": f"{self.response_time:.2f} seconds" if self.response_time is not None else "Not recorded"
        }
        return json.dumps(response_info, indent=4)

# Example usage
if __name__ == "__main__":
    start_time = time.time()
    response = HttpResponse(200, {"Content-Type": "application/json"}, '{"key": "value"}')
    response.record_timing(start_time)

    print(response.pretty_print())
    print("Success:", response.is_success())
    print("Parsed JSON:", response.parse_json())
