import json
import time
from typing import Dict, Any, Optional, Union
from datetime import datetime, timedelta


class HTTPResponse:
    def __init__(
        self,
        status_code: int,
        headers: Optional[Dict[str, str]] = None,
        body: Optional[Union[str, bytes]] = None,
        start_time: Optional[float] = None,
        end_time: Optional[float] = None
    ):
        self.status_code = status_code
        self.headers = headers or {}
        self.body = body or ""
        self.start_time = start_time or time.time()
        self.end_time = end_time or time.time()

    @property
    def elapsed_time(self) -> float:
        """Return the elapsed time in seconds."""
        return self.end_time - self.start_time

    @property
    def elapsed_ms(self) -> float:
        """Return the elapsed time in milliseconds."""
        return self.elapsed_time * 1000

    def is_success(self) -> bool:
        """Check if the response indicates success (2xx status codes)."""
        return 200 <= self.status_code < 300

    def is_client_error(self) -> bool:
        """Check if the response indicates a client error (4xx status codes)."""
        return 400 <= self.status_code < 500

    def is_server_error(self) -> bool:
        """Check if the response indicates a server error (5xx status codes)."""
        return 500 <= self.status_code < 600

    def is_redirect(self) -> bool:
        """Check if the response indicates a redirect (3xx status codes)."""
        return 300 <= self.status_code < 400

    def json(self) -> Any:
        """Parse the response body as JSON."""
        if isinstance(self.body, bytes):
            body_str = self.body.decode('utf-8')
        else:
            body_str = self.body

        try:
            return json.loads(body_str)
        except (json.JSONDecodeError, TypeError) as e:
            raise ValueError(f"Response body is not valid JSON: {e}")

    def get_header(self, name: str, default: Optional[str] = None) -> Optional[str]:
        """Get a header value by name (case-insensitive)."""
        name_lower = name.lower()
        for header_name, header_value in self.headers.items():
            if header_name.lower() == name_lower:
                return header_value
        return default

    def get_content_type(self) -> Optional[str]:
        """Get the Content-Type header value."""
        return self.get_header('content-type')

    def get_content_length(self) -> Optional[int]:
        """Get the Content-Length header value as an integer."""
        content_length = self.get_header('content-length')
        if content_length:
            try:
                return int(content_length)
            except ValueError:
                return None
        return None

    def __str__(self) -> str:
        """Return a pretty-printed string representation of the response."""
        lines = []
        lines.append(f"HTTP Response {self.status_code}")
        lines.append(f"Elapsed Time: {self.elapsed_ms:.2f}ms")
        lines.append("")

        if self.headers:
            lines.append("Headers:")
            for name, value in self.headers.items():
                lines.append(f"  {name}: {value}")
            lines.append("")

        if self.body:
            body_preview = str(self.body)
            if len(body_preview) > 500:
                body_preview = body_preview[:500] + "..."

            lines.append("Body:")
            # Try to pretty-print JSON
            try:
                if self.get_content_type() and 'json' in self.get_content_type().lower():
                    json_data = self.json()
                    body_preview = json.dumps(json_data, indent=2)
                    if len(body_preview) > 500:
                        body_preview = body_preview[:500] + "..."
            except (ValueError, AttributeError):
                pass

            lines.append(f"  {body_preview}")

        return "\n".join(lines)

    def __repr__(self) -> str:
        return (
            f"HTTPResponse(status_code={self.status_code}, "
            f"headers_count={len(self.headers)}, "
            f"body_length={len(str(self.body)) if self.body else 0}, "
            f"elapsed_ms={self.elapsed_ms:.2f})"
        )

    def to_dict(self) -> Dict[str, Any]:
        """Convert the response to a dictionary representation."""
        return {
            'status_code': self.status_code,
            'headers': self.headers,
            'body': self.body,
            'elapsed_time': self.elapsed_time,
            'elapsed_ms': self.elapsed_ms,
            'start_time': self.start_time,
            'end_time': self.end_time,
            'is_success': self.is_success(),
            'is_client_error': self.is_client_error(),
            'is_server_error': self.is_server_error(),
            'is_redirect': self.is_redirect()
        }
