        body: Union[str, bytes] = "",
        request_time: Optional[float] = None,
        response_time: Optional[float] = None
    ):
        self.status_code = status_code
        self.headers = headers or {}
        self.body = body
        self.request_time = request_time or time.time()
        self.response_time = response_time or time.time()

    @property
    def elapsed_time(self) -> float:
        """Returns the elapsed time in seconds between request and response."""
        return self.response_time - self.request_time

    @property
    def elapsed_timedelta(self) -> timedelta:
        """Returns the elapsed time as a timedelta object."""
        return timedelta(seconds=self.elapsed_time)

    def is_success(self) -> bool:
        """Returns True if the status code indicates success (200-299)."""
        return 200 <= self.status_code < 300

    def is_redirect(self) -> bool:
        """Returns True if the status code indicates a redirect (300-399)."""
        return 300 <= self.status_code < 400

    def is_client_error(self) -> bool:
        """Returns True if the status code indicates a client error (400-499)."""
        return 400 <= self.status_code < 500

    def is_server_error(self) -> bool:
        """Returns True if the status code indicates a server error (500-599)."""
        return 500 <= self.status_code < 600

    def get_header(self, name: str, default: Optional[str] = None) -> Optional[str]:
        """Returns the value of a header (case-insensitive) or default if not found."""
        for header_name, header_value in self.headers.items():
            if header_name.lower() == name.lower():
                return header_value
        return default

    def get_content_type(self) -> Optional[str]:
        """Returns the content type from headers."""
        return self.get_header("content-type")

    def get_body_text(self) -> str:
        """Returns the body as a string, decoding bytes if necessary."""
        if isinstance(self.body, bytes):
            return self.body.decode('utf-8', errors='replace')
        return str(self.body)

    def json(self) -> Any:
        """
        Parses the response body as JSON.

        Raises:
            json.JSONDecodeError: If the body cannot be parsed as JSON
        """
        body_text = self.get_body_text()
        return json.loads(body_text)

    def is_json(self) -> bool:
        """Returns True if the response appears to contain JSON data."""
        content_type = self.get_content_type()
        if content_type and "application/json" in content_type.lower():
            return True

        try:
            self.json()
            return True
        except (json.JSONDecodeError, ValueError):
            return False

    def pretty_print(self, include_body: bool = True, max_body_length: int = 1000) -> str:
        """
        Returns a pretty-printed string representation of the response.

        Args:
            include_body: Whether to include the response body
            max_body_length: Maximum length of body to display (truncated if longer)
        """
        lines = []

        # Status line
        lines.append(f"HTTP Response: {self.status_code}")

        # Timing information
        lines.append(f"Elapsed Time: {self.elapsed_time:.3f}s")
        lines.append(f"Request Time: {datetime.fromtimestamp(self.request_time).isoformat()}")
        lines.append(f"Response Time: {datetime.fromtimestamp(self.response_time).isoformat()}")

