                    if len(body_text) > max_body_length:
                        body_text = body_text[:max_body_length] + "... (truncated)"
                except (json.JSONDecodeError, ValueError):
                    pass

            # Indent body content
            body_lines = body_text.split('\n')
            for line in body_lines:
                lines.append(f"  {line}")

        return '\n'.join(lines)

    def __str__(self) -> str:
        return f"HTTPResponse(status={self.status_code}, elapsed={self.elapsed_time:.3f}s)"

    def __repr__(self) -> str:
        return (f"HTTPResponse(status_code={self.status_code}, "
                f"headers={self.headers}, "
                f"body_length={len(self.get_body_text())}, "
                f"elapsed_time={self.elapsed_time:.3f})")
